={{ (() => {
  const a = $('Parse AI').item.json.ai;
  const m = $('Prepare Mail').item.json;
  const icons = { kritisch: '🔴', hoch: '🟠', normal: '🟡', niedrig: '🟢' };
  const icon = icons[a.priority] || '📧';
  const prio = (a.priority || 'normal').toUpperCase();
  let msg = icon + ' *' + prio + ' – ' + (a.category || '–') + '*\n\n';
  msg += '*Von:* ' + (m.from || '–') + '\n';
  msg += '*Betreff:* ' + (m.subject || '–') + '\n\n';
  msg += (a.summary || '');
  if (a.task)            msg += '\n\n⚡ *Aktion:* ' + a.task;
  if (a.deadline)        msg += '\n📅 *Frist:* ' + a.deadline;
  if (a.suggested_reply) msg += '\n\n💬 *Antwortvorschlag:*\n_' + a.suggested_reply + '_';
  return msg;
})() }}

