const item = $input.first().json;
const subject = (item.subject || '').toLowerCase();
const from = (item.from || '').toLowerCase();
const text = (item.text || '').toLowerCase();

// Drop: Bestellbestätigungen, Login-Links, Newsletter, eigene Services
const skipSubject = [
  'bestellung', 'bestellbestätigung', 'order confirm', 'order #',
  'ihre bestellung', 'deine bestellung', 'tracking',
  'versandbestätigung', 'versand', 'shipment', 'shipped',
  'magic link', 'login link', 'sign in link', 'anmeldelink',
  'passwort', 'password reset', 'verify your', 'verifizier',
  'confirm your email', 'bestätige deine',
  'abonnement', 'unsubscribe', 'abmelden',
  'newsletter', 'gutschein', 'rabatt', 'angebot',
  'rechnung nr.', // auto-generated invoices handled separately
  'healthchecks', 'n8n', 'paperless', 'immich',
  'ihr paket', 'dein paket', 'paketnummer'
];

const skipFrom = [
  'noreply', 'no-reply', 'donotreply', 'do-not-reply',
  'orders@', 'shipping@', 'notifications@', 'mailer@',
  'amazon.', 'paypal.', 'dhl.', 'dpd.', 'ups.', 'hermes.',
  'otto.de', 'zalando', 'ebay.', 'idealo',
  'apple.com', 'google.com', 'microsoft.com',
  'github.com', 'cloudflare', 'hetzner'
];

const matchSubject = skipSubject.some(k => subject.includes(k));
const matchFrom   = skipFrom.some(k => from.includes(k));

if (matchSubject || matchFrom) {
  // Silently drop — return empty array
  return [];
}

return [$input.first()];

